#include <bits/stdc++.h>
using namespace std;
long long n,m,t[400005],tab[400005];
void push_bown(int u,int l,int r)
{
	if(!tab[u]) return ;
	int ls=u*2,rs=u*2+1,mid=(l+r)>>1;
	t[ls]=mid-l+1-t[ls];
	tab[ls]^=1;
	t[rs]=r-mid-t[rs];
	tab[rs]^=1;
	tab[u]=0;
}
void fun(int u,int l,int r,int x,int y)
{
	if(l>y||r<x) return ;
	if(l>=x&&r<=y)
	{
		t[u]=r-l+1-t[u];
		tab[u]^=1;
		return ;
	}
	int mid=(l+r)>>1;
	push_bown(u,l,r);
	fun(u*2,l,mid,x,y);
	fun(u*2+1,mid+1,r,x,y);
	t[u]=t[u*2]+t[u*2+1];
}
long long sum(int u,int l,int r,int x,int y)
{
	if(l>y||r<x) return 0;
	if(l>=x&&r<=y) return t[u];
	push_bown(u,l,r);
	int mid=(l+r)>>1;
	return sum(u*2,l,mid,x,y)+sum(u*2+1,mid+1,r,x,y);
}
int main()
{
	cin>>n>>m;
	while(m--)
	{
		int op;
		cin>>op;
		if(op==0)
		{
			int x,y;
			cin>>x>>y;
			fun(1,1,n,x,y);
		}
		else
		{
			int x,y;
			cin>>x>>y;
			cout<<sum(1,1,n,x,y)<<'\n';
		}
	}
	return 0;
}
